import { useRef, useEffect, useState } from 'react';
import type { PointerEvent } from 'react';
import { useTabletop } from './TabletopContext';
import { Token } from './Token';
import { ScenarioObject } from './ScenarioObject';
import { SQUARE_SIZE, GRID_WIDTH, GRID_HEIGHT } from './constants';
import { ZoomIn, ZoomOut, Maximize2 } from 'lucide-react';

const MIN_ZOOM = 0.3;
const MAX_ZOOM = 2.5;

// Preset map themes — pure CSS & SVG patterns (no external images required)
const PRESET_MAPS: { label: string; bg: string; grid?: string }[] = [
  { label: 'Calabouço',     bg: '#1a1a24' },
  { label: 'Floresta',      bg: '#1a2f1a' },
  { label: 'Deserto',       bg: '#3d2b12' },
  { label: 'Oceano',        bg: '#0a1f35' },
  { label: 'Lava',          bg: '#2d0a0a' },
  { label: 'Neve',          bg: '#1e2a30' },
];

export const MapBoard = () => {
  const {
    state, setState, isLoaded,
    activeColor, toggleGridMarking,
    setSelectedCharacterId, setSelectedMapObjectId,
  } = useTabletop();

  const containerRef = useRef<HTMLDivElement>(null);

  // fit-to-screen base scale
  const [fitScale, setFitScale] = useState(1);
  // user additional zoom on top of fit
  const [zoomLevel, setZoomLevel] = useState(1);

  const boardWidth  = GRID_WIDTH  * SQUARE_SIZE;
  const boardHeight = GRID_HEIGHT * SQUARE_SIZE;
  const totalScale  = fitScale * zoomLevel;

  // Compute fit-to-screen scale and block Ctrl+scroll browser zoom
  useEffect(() => {
    if (!isLoaded) return;
    const el = containerRef.current;
    if (!el) return;

    const updateFit = () => {
      const padding = 40;
      const scaleX = (el.clientWidth  - padding) / boardWidth;
      const scaleY = (el.clientHeight - padding) / boardHeight;
      setFitScale(Math.min(scaleX, scaleY));
    };

    const ro = new ResizeObserver(updateFit);
    ro.observe(el);
    updateFit();

    const handleWheel = (e: WheelEvent) => {
      e.preventDefault(); // Block both Ctrl+scroll browser zoom and unintended page scroll

      if (e.ctrlKey || !e.ctrlKey) {
        // Zoom in/out with scroll
        const delta = e.deltaY > 0 ? -0.1 : 0.1;
        setZoomLevel(prev => Math.min(MAX_ZOOM, Math.max(MIN_ZOOM / fitScale, prev + delta)));
      }
    };

    el.addEventListener('wheel', handleWheel, { passive: false });
    return () => {
      ro.disconnect();
      el.removeEventListener('wheel', handleWheel);
    };
  }, [isLoaded, boardWidth, boardHeight, fitScale]);

  const handlePointerDown = (e: PointerEvent<HTMLDivElement>) => {
    if ((e.target as HTMLElement).closest('[data-no-map-click]')) return;

    if (
      e.target === e.currentTarget ||
      (e.target as HTMLElement).id === 'tabletop-board-bg' ||
      (e.target as HTMLElement).id === 'tabletop-board'
    ) {
      setSelectedCharacterId(null);
      setSelectedMapObjectId(null);
    }

    if (activeColor) {
      const boardElement = document.getElementById('tabletop-board');
      if (boardElement) {
        const rect = boardElement.getBoundingClientRect();
        const boardRenderScale = rect.width / boardElement.offsetWidth;
        const xOnBoard = (e.clientX - rect.left) / boardRenderScale;
        const yOnBoard = (e.clientY - rect.top)  / boardRenderScale;
        const gridX = Math.floor(xOnBoard / SQUARE_SIZE);
        const gridY = Math.floor(yOnBoard / SQUARE_SIZE);
        if (gridX >= 0 && gridX < GRID_WIDTH && gridY >= 0 && gridY < GRID_HEIGHT) {
          toggleGridMarking(gridX, gridY, activeColor);
        }
      }
    }
  };

  const resetZoom = () => setZoomLevel(1);

  // Derive background from state (custom upload takes priority)
  const bgStyle: React.CSSProperties = state.backgroundImageUrl
    ? { backgroundImage: `url(${state.backgroundImageUrl})`, backgroundSize: 'cover', backgroundPosition: 'center' }
    : { backgroundColor: state.mapPresetColor ?? '#1a1a24' };

  if (!isLoaded) {
    return (
      <div className="flex-1 w-full h-full flex items-center justify-center bg-[#0d0d12]">
        <span className="text-white">Carregando Tabuleiro...</span>
      </div>
    );
  }

  return (
    <div
      ref={containerRef}
      className="relative w-full h-full bg-[#0d0d12] overflow-hidden flex items-center justify-center"
      onPointerDown={handlePointerDown}
    >
      {/* ── Preset Map Selector (top-centre) ── */}
      <div
        data-no-map-click
        className="absolute top-3 left-1/2 -translate-x-1/2 z-50 flex gap-1 bg-black/60 px-2 py-1 rounded-full border border-[#2d1b4e]/70 backdrop-blur-sm"
      >
        {PRESET_MAPS.map(map => (
          <button
            key={map.label}
            title={map.label}
            onClick={() => setState(prev => ({ ...prev, backgroundImageUrl: null, mapPresetColor: map.bg }))}
            className={`px-2 py-0.5 rounded-full text-[10px] font-medium transition-all border ${
              !state.backgroundImageUrl && (state.mapPresetColor ?? '#1a1a24') === map.bg
                ? 'border-[#9d4edd] bg-[#9d4edd]/30 text-white'
                : 'border-transparent text-gray-400 hover:text-white hover:border-[#2d1b4e]'
            }`}
          >
            {map.label}
          </button>
        ))}
      </div>

      {/* ── Zoom controls (bottom-right) ── */}
      <div
        data-no-map-click
        className="absolute bottom-4 right-4 z-50 flex flex-col gap-2"
      >
        <button
          onClick={() => setZoomLevel(z => Math.min(MAX_ZOOM, z + 0.15))}
          className="w-8 h-8 flex items-center justify-center rounded bg-black/60 border border-[#2d1b4e] text-white hover:border-[#9d4edd] hover:text-[#9d4edd] transition-colors"
          title="Aumentar zoom"
        >
          <ZoomIn size={16} />
        </button>
        <button
          onClick={resetZoom}
          className="w-8 h-8 flex items-center justify-center rounded bg-black/60 border border-[#2d1b4e] text-white hover:border-[#9d4edd] hover:text-[#9d4edd] transition-colors text-[10px] font-mono"
          title="Resetar zoom"
        >
          <Maximize2 size={14} />
        </button>
        <button
          onClick={() => setZoomLevel(z => Math.max(MIN_ZOOM, z - 0.15))}
          className="w-8 h-8 flex items-center justify-center rounded bg-black/60 border border-[#2d1b4e] text-white hover:border-[#9d4edd] hover:text-[#9d4edd] transition-colors"
          title="Diminuir zoom"
        >
          <ZoomOut size={16} />
        </button>
        {/* Zoom indicator */}
        <div className="text-center text-[9px] font-mono text-gray-500">
          {Math.round(zoomLevel * 100)}%
        </div>
      </div>

      {/* ── Board ── */}
      <div
        id="tabletop-board"
        className="relative shrink-0 select-none shadow-[0_0_60px_rgba(45,27,78,0.9)] border-4 border-[#2d1b4e] rounded-lg overflow-hidden z-10"
        style={{
          width: boardWidth,
          height: boardHeight,
          transform: `scale(${totalScale})`,
          transformOrigin: 'center center',
          ...bgStyle,
        }}
      >
        <div id="tabletop-board-bg" className="absolute inset-0 z-0" />

        {/* Tokens & Objects (pointer-events enabled by children) */}
        <div className="absolute inset-0 z-20 pointer-events-none">
          {(state.mapObjects || []).map(obj => <ScenarioObject key={obj.id} object={obj} />)}
          {(state.characters || []).map(char => <Token key={char.id} character={char} />)}
        </div>

        {/* Grid Markings */}
        {Object.entries(state.gridMarkings || {}).map(([key, color]) => {
          const [x, y] = key.split(',').map(Number);
          return (
            <div
              key={key}
              className="absolute pointer-events-none z-10 opacity-60 mix-blend-screen"
              style={{
                top: y * SQUARE_SIZE,
                left: x * SQUARE_SIZE,
                width: SQUARE_SIZE,
                height: SQUARE_SIZE,
                backgroundColor: color,
              }}
            />
          );
        })}

        {/* Grid Lines */}
        <div
          className="absolute inset-0 pointer-events-none z-30 opacity-30"
          style={{
            backgroundImage: `
              linear-gradient(to right, rgba(255,255,255,0.4) 1px, transparent 1px),
              linear-gradient(to bottom, rgba(255,255,255,0.4) 1px, transparent 1px)
            `,
            backgroundSize: `${SQUARE_SIZE}px ${SQUARE_SIZE}px`,
          }}
        />
      </div>
    </div>
  );
};
