import { useState } from 'react';
import type { PointerEvent } from 'react';
import type { Character } from './types';
import { SQUARE_SIZE } from './constants';
import { useTabletop } from './TabletopContext';

type TokenProps = {
  character: Character;
};

export const Token = ({ character }: TokenProps) => {
  const { setSelectedCharacterId, selectedCharacterId, updateCharacter, deleteCharacter, isSpacePressed } = useTabletop();
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const isSelected = selectedCharacterId === character.id;
  const hpPercent = Math.max(0, Math.min(100, (character.hp / character.maxHp) * 100));

  const renderedX = (isDragging ? dragOffset.x : character.position.x) * SQUARE_SIZE;
  const renderedY = (isDragging ? dragOffset.y : character.position.y) * SQUARE_SIZE;
  const tokenSizePx = SQUARE_SIZE;
  const visualScale = Number(character.size) || 1;

  const handlePointerDown = (e: PointerEvent<HTMLDivElement>) => {
    e.stopPropagation();
    if (e.button === 2) {
      e.preventDefault();
      updateCharacter(character.id, { rotation: (character.rotation + 90) % 360 });
      return;
    }
    if (isSpacePressed) return;

    if (e.button === 0) {
      setSelectedCharacterId(character.id);
      setIsDragging(true);
      setDragOffset({ x: character.position.x, y: character.position.y });

      const pointerId = e.pointerId;
      const el = e.currentTarget;
      el.setPointerCapture(pointerId);

      const startClientX = e.clientX;
      const startClientY = e.clientY;
      const startX = character.position.x;
      const startY = character.position.y;

      const boardElement = document.getElementById('tabletop-board');
      let boardScale = 1;
      if (boardElement) {
        boardScale = boardElement.getBoundingClientRect().width / boardElement.offsetWidth;
      }

      const onPointerMove = (moveEvent: globalThis.PointerEvent) => {
        const dx = (moveEvent.clientX - startClientX) / boardScale;
        const dy = (moveEvent.clientY - startClientY) / boardScale;
        setDragOffset({
          x: startX + dx / SQUARE_SIZE,
          y: startY + dy / SQUARE_SIZE,
        });
      };

      const onPointerUp = (upEvent: globalThis.PointerEvent) => {
        el.releasePointerCapture(pointerId);
        el.removeEventListener('pointermove', onPointerMove);
        el.removeEventListener('pointerup', onPointerUp);
        setIsDragging(false);

        const dx = (upEvent.clientX - startClientX) / boardScale;
        const dy = (upEvent.clientY - startClientY) / boardScale;
        const finalX = Math.round(startX + dx / SQUARE_SIZE);
        const finalY = Math.round(startY + dy / SQUARE_SIZE);
        updateCharacter(character.id, { position: { x: finalX, y: finalY } });
      };

      el.addEventListener('pointermove', onPointerMove);
      el.addEventListener('pointerup', onPointerUp);
    }
  };

  return (
    <div
      onPointerDown={handlePointerDown}
      onContextMenu={(e: React.MouseEvent) => { e.preventDefault(); }}
      className={`absolute top-0 left-0 cursor-pointer select-none pointer-events-auto ${isDragging ? 'z-50 opacity-80' : 'z-20'}`}
      style={{
        width: `${tokenSizePx}px`,
        height: `${tokenSizePx}px`,
        transform: `translate(${renderedX}px, ${renderedY}px)`,
        transformOrigin: 'top left',
      }}
    >
      {/* Selection highlight at tile level */}
      {isSelected && !isDragging && (
        <div className="absolute inset-0 ring-2 ring-yellow-400/70 bg-yellow-400/10 rounded z-10 pointer-events-none" />
      )}

      {/* Image — scales in ALL 4 directions from center */}
      <div
        className="absolute pointer-events-none drop-shadow-lg"
        style={{
          width: `${tokenSizePx}px`,
          height: `${tokenSizePx}px`,
          top: '50%',
          left: '50%',
          transform: `translate(-50%, -50%) scale(${visualScale}) rotate(${character.rotation}deg)`,
          transformOrigin: 'center center',
          backgroundImage: `url(${character.imageUrl})`,
          backgroundSize: 'contain',
          backgroundPosition: 'center',
          backgroundRepeat: 'no-repeat',
          transition: isDragging ? 'none' : 'transform 0.2s',
        }}
      />

      {/* HP Bar — always at tile position */}
      <div className="absolute -top-3 left-0 right-0 h-2 bg-red-950/80 border border-black/50 rounded overflow-hidden z-30 pointer-events-none">
        <div className="h-full bg-red-500 transition-all duration-300" style={{ width: `${hpPercent}%` }} />
      </div>

      {/* Name label */}
      <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 whitespace-nowrap bg-black/70 px-2 py-0.5 rounded text-xs text-white font-medium pointer-events-none z-30">
        {character.name}
      </div>

      {/* Delete button (selected only) */}
      {isSelected && (
        <button
          onClick={(e) => { e.stopPropagation(); deleteCharacter(character.id); }}
          className="absolute -top-8 -right-4 bg-red-600 hover:bg-red-500 text-white rounded-full w-6 h-6 flex items-center justify-center font-bold shadow-md z-40"
        >
          ×
        </button>
      )}
    </div>
  );
};
