import { useTabletop } from './TabletopContext';
import { Image, Brush, Trash2 } from 'lucide-react';

const COLORS = [
  { name: 'Amarelo', value: '#ffff00' },
  { name: 'Verde', value: '#00ff00' },
  { name: 'Azul', value: '#0000ff' },
  { name: 'Vermelho', value: '#ff0000' },
  { name: 'Branco', value: '#ffffff' },
  { name: 'Preto', value: '#000000' },
];

export const LeftSidebar = () => {
  const { 
    state, 
    setState, 
    activeColor, 
    setActiveColor, 
    clearGridMarkings,
  } = useTabletop();

  const handleBgUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => setState(prev => ({ ...prev, backgroundImageUrl: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="w-[18rem] min-w-[18rem] max-w-[18rem] shrink-0 h-full bg-[#111116] border-r border-[#2d1b4e]/50 p-4 flex flex-col gap-6 overflow-y-auto text-sm text-gray-300">
      
      {/* Background Section */}
      <div className="space-y-2">
        <h3 className="font-bold text-white flex items-center gap-2"><Image size={16} /> Mapa de Fundo</h3>
        <p className="text-xs text-gray-400">Faça o upload da imagem do seu mapa.</p>
        <div className="mt-2">
          <label className="flex items-center justify-center w-full bg-[#2d1b4e]/50 hover:bg-[#9d4edd]/50 border border-[#2d1b4e] hover:border-[#9d4edd] text-white py-2 rounded cursor-pointer transition-colors">
            Carregar Imagem Base
            <input 
              type="file" 
              accept="image/*"
              className="hidden"
              onChange={handleBgUpload}
            />
          </label>
        </div>
        {state.backgroundImageUrl && (
          <button 
            onClick={() => setState(prev => ({ ...prev, backgroundImageUrl: null }))}
            className="text-red-400 hover:text-red-300 text-xs mt-2 w-full text-center"
          >
            Remover Mapa
          </button>
        )}
      </div>

      <hr className="border-[#2d1b4e]/30" />

      {/* Grid Markings Section */}
      <div className="space-y-2">
        <h3 className="font-bold text-white flex items-center gap-2"><Brush size={16} /> Marcações no Grid</h3>
        <p className="text-xs text-gray-400">Clique na cor e depois clique nos quadrados do grid para pintar áreas de efeito.</p>
        <div className="flex flex-wrap gap-2 mt-2">
          {COLORS.map(c => (
             <button 
               key={c.value} 
               onClick={() => setActiveColor(activeColor === c.value ? null : c.value)}
               className={`w-8 h-8 rounded-full border-2 transition-transform ${activeColor === c.value ? 'scale-110 border-blue-500' : 'border-black/50'} hover:scale-105`}
               style={{ backgroundColor: c.value }}
               title={c.name}
             />
          ))}
        </div>
        {(activeColor || Object.keys(state.gridMarkings).length > 0) && (
          <div className="flex justify-between items-center mt-4">
            {activeColor && (
              <button 
                onClick={() => setActiveColor(null)}
                className="text-gray-400 hover:text-white text-xs border border-gray-600 px-2 py-1 rounded"
              >
                Cancelar Pintura
              </button>
            )}
            {Object.keys(state.gridMarkings).length > 0 && (
              <button 
                onClick={clearGridMarkings}
                className="text-red-400 hover:text-red-300 text-xs flex items-center gap-1"
              >
                <Trash2 size={12} /> Limpar Tudo
              </button>
            )}
          </div>
        )}
      </div>

    </div>
  );
};
